// export default Contact






import React from "react";
import { contact, section5Title, social } from "../../profile";

const Contact = () => {
  return (
    <div className="parallax">
      <div data-aos="zoom-in-up" data-aos-once="true" className="git-form">
        <>
          <div className="git-head-div text-center mx-auto">
            <h1 id="Contact" className="git-head">
              {section5Title}
            </h1>
          </div>
        </>
        <div className="container">
          <div className="git-cont row">
            <div className="col-12 col-sm-6 half">
              <form
                action={
                  contact.contactUrl
                    ? contact.contactUrl
                    : "https://formspree.io"
                }
                method={contact.contactUrl ? "POST" : "GET"}
              >
                <input
                  type="text"
                  id="fname"
                  name="firstname"
                  placeholder="Your name"
                  required
                ></input>
                <input
                  type="mail"
                  id="mailid"
                  name="Email"
                  placeholder="Email Address"
                  required
                ></input>
                <input
                  type="text"
                  id="sub"
                  name="Subject"
                  placeholder="Subject"
                  required
                ></input>
                <textarea
                  id="msg"
                  name="message"
                  placeholder="Message"
                  required
                ></textarea>
                <button className="but" style={{ cursor: "pointer" }} type="submit">
                  Send Message
                </button>
              </form>
            </div>
            <div className="col-12 col-sm-6 half">
              <p className="lead">{contact.pitch}</p>
              
              <div className="d-flex justify-content-center align-items-center flex-column">
                <div className="inline-block contactInfo">
                  {social.Gmail && (
                    <h6
                      className=".git-cont .fab"
                      title="Visit Facebok profile"
                      rel="noopener noreferrer"
                      target="_blank"
                      href={social.Gmail}
                    >
                      <i className="fab fa fa-envelope"></i>
                      Swarnakarsweta@gmail.com
                    </h6>
                  )}
                  {social.phone && (
                    <h6
                      className=".git-cont .fab"
                      title="Visit Facebok profile"
                      rel="noopener noreferrer"
                      target="_blank"
                      href={social.phone}
                    >
                      <i className="fab fa fa-phone"></i>+91 8373043127
                    </h6>
                  )}
                  {social.linkedin && (
                    <h6
                      title="Visit Linkedin profile"
                      rel="noopener noreferrer"
                    >
                      <a href={social.linkedin} target="_blank">
                        <i className="fab fa-linkedin"></i>
                      </a>
                      Sweta Swarnakar
                    </h6>
                  )}

                  {social.facebook && (
                    <h6
                      title="Visit Instagram profile"
                      rel="noopener noreferrer"
                    >
                      <a href={social.instagram} target="_blank">
                        <i className="fab fa-facebook"></i>
                      </a>
                      Sweta Swarnakar
                    </h6>
                  )}
                  {social.github && (
                    <h6 title="Visit Github profile" rel="noopener noreferrer">
                      <a href={social.github} target="_blank">
                        <i className="fab fa-github"></i>
                      </a>
                      Sweta Swarnakar
                    </h6>
                  )}
                  {social.resume && (
                    <a title="Download Resume" href={social.resume} download>
                      <i className="fas fa-download"></i>
                    </a>
                  )}
                </div>
              </div>
            </div>
          </div>
        </div>
      </div>
      <p id="not-dark" className="Copy">
        2022 © Copyright <strong>Sweta Swarnakar</strong>. All Rights
        Reserved
      </p>
    </div>
  );
};

export default Contact;

